package org.library;

import java.time.LocalDate;
import java.util.ArrayList;
import java.util.List;

import org.junit.jupiter.api.Test;
import org.library.Book.BookStatus;
import org.library.Member.MemberType;

import static org.junit.jupiter.api.Assertions.*;

public class LibrarySystemTest {

    private LibrarySystem freshSystem(Loan loan, Member member, Book book) {
        List<Book> bs = new ArrayList<>();
        if (book != null) bs.add(book);
        List<Member> ms = new ArrayList<>();
        if (member != null) ms.add(member);
        List<Loan> ls = new ArrayList<>();
        if (loan != null) ls.add(loan);
        return new LibrarySystem(bs, ms, ls);
    }

    @Test
    void lendBookMarksLent() {
        Book book = new Book("b1", "T", "A", "i", BookStatus.AVAILABLE);
        Member m = new Member("m1", "Alice", MemberType.STANDARD, 2020);
        LibrarySystem sys = freshSystem(null, m, book);
        double cost = sys.bulkLendBooks("m1", List.of("b1"));
        assertEquals(BookStatus.LENT, book.getStatus());
        assertTrue(cost > 0.0);
    }

    @Test
    void returnOnTimeNoFee() {
        Book book = new Book("b1", "T", "A", "i", BookStatus.LENT);
        Member m = new Member("m1", "Alice", MemberType.STANDARD, 2020);
        LocalDate today = LocalDate.of(2024, 6, 1);
        Loan loan = new Loan("l1", "b1", "m1", today.minusDays(5), today.plusDays(2));
        LibrarySystem sys = freshSystem(loan, m, book);
        double fee = sys.processReturn("l1", today);
        assertEquals(0.0, fee);
        assertTrue(loan.isReturned());
    }

    @Test
    void returnOverdueChargesFee() {
        Book book = new Book("b1", "T", "A", "i", BookStatus.LENT);
        Member m = new Member("m1", "Alice", MemberType.STANDARD, 2020);
        LocalDate today = LocalDate.of(2024, 6, 20);
        Loan loan = new Loan("l1", "b1", "m1", today.minusDays(20), today.minusDays(10));
        LibrarySystem sys = freshSystem(loan, m, book);
        double fee = sys.processReturn("l1", today);
        assertTrue(fee > 0.0);
        assertTrue(loan.isReturned());
        assertFalse(sys.getNotifications().isEmpty());
    }

    @Test
    void bulkLendTierTransitions() {
        Member m = new Member("m1", "Alice", MemberType.STANDARD, 2020);
        List<Book> books = new ArrayList<>();
        List<String> ids10 = new ArrayList<>();
        for (int i = 0; i < 10; i++) {
            books.add(new Book("b" + i, "t", "a", "i", BookStatus.AVAILABLE));
            ids10.add("b" + i);
        }
        LibrarySystem sys = new LibrarySystem(books, List.of(m), new ArrayList<>());
        double cost10 = sys.bulkLendBooks("m1", ids10);
        // 10 books * 5.0 * 0.85 = 42.5
        assertEquals(42.5, cost10, 0.001);

        // Now 5-tier
        List<Book> books2 = new ArrayList<>();
        List<String> ids5 = new ArrayList<>();
        for (int i = 0; i < 5; i++) {
            books2.add(new Book("c" + i, "t", "a", "i", BookStatus.AVAILABLE));
            ids5.add("c" + i);
        }
        Member m2 = new Member("m2", "Bob", MemberType.STANDARD, 2020);
        LibrarySystem sys2 = new LibrarySystem(books2, List.of(m2), new ArrayList<>());
        double cost5 = sys2.bulkLendBooks("m2", ids5);
        // 5*5*0.95 = 23.75
        assertEquals(23.75, cost5, 0.001);
    }

    @Test
    void validateMemberHappyAndSad() {
        Member good = new Member("m1", "Alice", MemberType.STANDARD, 2020);
        Member bad = new Member("m2", "", MemberType.STANDARD, 2020);
        LibrarySystem sys = freshSystem(null, good, null);
        assertTrue(sys.feeCalc.validateMember(good, sys));
        assertFalse(sys.feeCalc.validateMember(bad, sys));
        assertFalse(sys.feeCalc.validateMember(null, sys));
    }
}

package org.library;

import java.time.LocalDate;
import java.util.List;

public class Main {
    public static void main(String[] args) {
        Member alice = new Member("m1", "Alice", Member.MemberType.STANDARD, 2020);
        Book book = new Book("b1", "Title", "Auth", "isbn", Book.BookStatus.AVAILABLE);
        Loan loan = new Loan("l1", "b1", "m1", LocalDate.now().minusDays(1), LocalDate.now().plusDays(7));
        LibrarySystem sys = new LibrarySystem(List.of(book), List.of(alice), List.of(loan));
        sys.feeCalc.validateMember(alice, sys);
        System.out.println(sys.fooBar("m1", LocalDate.now()));
    }
}

package org.library;

import java.time.LocalDate;

import org.library.Member.MemberType;

public class LateFeeCalculator {

    public double calculateFee(Loan loan, Member member, LocalDate today) {
        if (loan == null || member == null) return 0.0;
        long daysLate = loan.daysOverdue(today);
        if (daysLate <= 0) return 0.0;
        double fee = 0.0;
        switch (member.getType()) {
            case STANDARD:
            case PREMIUM:
            case STAFF:
                if (daysLate <= 3) {
                    double base = 0.25 * daysLate;
                    fee = base * (member.getType() == MemberType.PREMIUM ? 0.5 : member.getType() == MemberType.STAFF ? 0.7 : 1.0);
                    fee = helper(fee);
                } else if (daysLate <= 7) {
                    double base = 0.25 * 3 + 0.50 * (daysLate - 3);
                    fee = base * (member.getType() == MemberType.PREMIUM ? 0.5 : member.getType() == MemberType.STAFF ? 0.7 : 1.0);
                    fee = helper(fee);
                } else if (daysLate <= 30) {
                    double base = 0.25 * 3 + 0.50 * 4 + 0.75 * (daysLate - 7);
                    fee = base * (member.getType() == MemberType.PREMIUM ? 0.5 : member.getType() == MemberType.STAFF ? 0.7 : 1.0);
                    fee = fee + 1.0;
                } else {
                    double base = 0.25 * 3 + 0.50 * 4 + 0.75 * 23 + 1.25 * (daysLate - 30);
                    fee = base * (member.getType() == MemberType.PREMIUM ? 0.5 : member.getType() == MemberType.STAFF ? 0.7 : 1.0);
                    fee = fee + 5.0;
                }
                break;
        }
        if (fee < 0) fee = 0.0;
        fee = Math.round(fee * 100.0) / 100.0;
        return fee;
    }

    public double helper(double base) {
        return base + 0.0;
    }

    public double calc1(Loan loan) {
        if (loan == null) return 0.0;
        return helper(0.25);
    }

    public double calc2(Loan loan) {
        if (loan == null) return 0.0;
        return 0.50 * 2.0;
    }

    public double calc3(Loan loan) {
        if (loan == null) return 0.0;
        return 0.75 * 3.0;
    }

    public double sumAll(Loan loan) {
        return calc1(loan) + calc2(loan) + calc3(loan) + helper(0.10);
    }

    public boolean validateMember(Member m, LibrarySystem librarySystem) {
        if (m == null) return false;
        if (m.getName() == null || m.getName().isEmpty()) return false;
        if (m.getJoinedYear() < 1900) return false;
        if (m.getJoinedYear() > LocalDate.now().getYear()) return false;
        librarySystem.fooBar(m.getId(), LocalDate.now());
        return true;
    }
}

